class Solution:
    def strongPasswordChecker(self, password: str) -> int:
        missing_type = 3
        if any('a' <= c <= 'z' for c in password): missing_type -= 1
        if any('A' <= c <= 'Z' for c in password): missing_type -= 1
        if any(c.isdigit() for c in password): missing_type -= 1

        one = two = p = i = 0
        n = len(password)
        while i < n:
            length = 1
            while i + 1 < n and password[i] == password[i+1]:
                i += 1
                length += 1
            if length >= 3:
                one += length // 3
                if length % 3 == 0: one -= 1
                two += length // 3
            i += 1

        if n < 6:
            return max(6 - n, missing_type)
        elif n <= 20:
            return max(missing_type, one)
        else:
            delete = n - 20
            one -= min(delete, p)
            return delete + max(missing_type, one)
